const d = $input.first().json;
const category = (d.category || '').toLowerCase();

// ── RISK CLASSIFICATION (per Sam's Club 2025/2026 SOPs) ──
const isFoodOrSupp = category.includes('food') || category.includes('beverage') || category.includes('supplement') || category.includes('wellness');
const isElectronics = category.includes('electronic');
const isHouseholdOrPet = category.includes('home') || category.includes('pet') || category.includes('auto') || category.includes('office');

// Food risk levels per Food Safety SOP 2025
// Elevated High Risk: raw proteins, fresh produce, raw seafood, raw meat — NOT ALLOWED for Pop-Up
// Medium Risk: reheated items, cold/hot holding, pre-cooked proteins, dairy, cut fruits
// Low Risk: shelf-stable, pre-packaged, served in original packaging
let foodRiskLevel = 'N/A';
if (isFoodOrSupp) {
  // Default to Medium unless we know otherwise — safe assumption for roadshow food
  foodRiskLevel = 'Medium';
}

// GMF risk levels per GMF Product Testing SOP 2026
// Elevated High Risk: Natural Gas, Propane, Gasoline powered — NOT ALLOWED
// Medium Risk: lithium-ion batteries, OTC, consumables, wellness, household care
// Low Risk: non-powered, textile, plastic, glass, ceramic, metallic, wood, paper
let gmfRiskLevel = 'N/A';
if (!isFoodOrSupp) {
  gmfRiskLevel = isElectronics ? 'Medium' : 'Low';
}

// ── UNIVERSAL REQUIREMENTS (all brands) ──
const checklist = [
  { item: 'Ascenda Services Agreement (Signed)', required: true, status: 'pending', stage: 'Stage 0', category: 'all' },
  { item: 'Certificate of Insurance ($2M+ general liability)', required: true, status: d.hasInsurance === 'yes' ? 'received' : 'pending', stage: 'Stage 1', category: 'all' },
  { item: 'Product Photos (hi-res, white background)', required: true, status: 'pending', stage: 'Stage 1', category: 'all' },
  { item: 'UPC/GS1 Barcodes Registered', required: true, status: 'pending', stage: 'Stage 1', category: 'all' },
  { item: 'Product Spec Sheet', required: true, status: 'pending', stage: 'Stage 1', category: 'all' },
  { item: 'COGS Breakdown', required: true, status: d.canProvideCOGS === 'yes' ? 'received' : 'pending', stage: 'Stage 1', category: 'all' },
  { item: 'Current P&L (last 12 months)', required: true, status: 'pending', stage: 'Stage 1', category: 'all' },
  { item: 'Retail Distribution List (existing)', required: false, status: 'pending', stage: 'Stage 1', category: 'all' },
  { item: 'Customer Testimonials / Reviews', required: false, status: 'pending', stage: 'Stage 1', category: 'all' },
];

// ── FOOD SAFETY REQUIREMENTS (per Food Safety SOP 2025 + Questionnaire) ──
if (isFoodOrSupp) {
  checklist.push(
    { item: 'COMPLETED: Vendor Food Safety Questionnaire (Sam\'s Club 2025)', required: true, status: 'pending', stage: 'Stage 1', category: 'food' },
    { item: 'GFSI-recognized Certification OR Global Markets Audit OR Third-Party Audit (renewed annually)', required: true, status: 'pending', stage: 'Stage 1', category: 'food' },
    { item: 'Health Department License/Permit for EACH event location (vendor responsibility to contact local jurisdiction)', required: true, status: 'pending', stage: 'Stage 1', category: 'food' },
    { item: 'Food Safety Manager Certification (must be present at event — approved certs: AAA Food Safety, Learn2Serve, ServSafe, etc.)', required: true, status: 'pending', stage: 'Stage 1', category: 'food' },
    { item: 'Food Handler Permits/Cards (if required by local jurisdiction)', required: true, status: 'pending', stage: 'Stage 1', category: 'food' },
    { item: 'FDA / USDA Compliance Certification', required: true, status: 'pending', stage: 'Stage 1', category: 'food' },
    { item: 'Ingredient Statement with NINE Major Allergens documented (Peanuts, Wheat, Soybeans, Fish, Crustacean Shellfish, Tree Nuts, Milk, Eggs, Sesame)', required: true, status: d.nutritionalLabel === 'yes' ? 'received' : 'pending', stage: 'Stage 1', category: 'food' },
    { item: 'Food Preparation SOP (transport, cooking temps, temp/time logs, handwashing, gloves/hairnets, equipment)', required: true, status: 'pending', stage: 'Stage 1', category: 'food' },
    { item: 'Equipment List (handwashing station, calibrated metal stem thermometer, ware washing area)', required: true, status: 'pending', stage: 'Stage 1', category: 'food' },
    { item: 'Storage Method Documentation (refrigeration, freezer, dry storage)', required: true, status: 'pending', stage: 'Stage 1', category: 'food' },
    { item: 'Sam\'s Club Basic Food Safety High Five Training Acknowledgment', required: true, status: 'pending', stage: 'Stage 1', category: 'food' },
    { item: 'Sampling Plan Documentation', required: true, status: 'pending', stage: 'Stage 1', category: 'food' }
  );
}

// ── GENERAL MERCHANDISE REQUIREMENTS (per GMF Product Testing SOP 2026) ──
if (!isFoodOrSupp) {
  checklist.push(
    { item: 'C63 Product Testing via Approved Third-Party Lab (UL, SGS, Intertek, or Bureau Veritas)', required: true, status: 'pending', stage: 'Stage 1', category: 'gmf' },
    { item: 'Performance Testing Report (ISO 17025 accredited lab, dated within 12 months)', required: true, status: 'pending', stage: 'Stage 1', category: 'gmf' },
    { item: 'Regulatory Compliance Testing (per Walmart Inc. requirements)', required: true, status: 'pending', stage: 'Stage 1', category: 'gmf' },
    { item: 'Claims Testing Documentation (if applicable)', required: false, status: 'pending', stage: 'Stage 1', category: 'gmf' },
    { item: 'C63 Merchant Team Packaging Approval (retail-ready packaging)', required: true, status: 'pending', stage: 'Stage 1', category: 'gmf' },
    { item: 'Sam\'s Club Structural Packaging Standards Compliance (PDQ display / pallet construction)', required: true, status: 'pending', stage: 'Stage 1', category: 'gmf' },
    { item: 'FedEx ISTA6 Transit Testing (if applicable per lab review)', required: false, status: 'pending', stage: 'Stage 1', category: 'gmf' },
    { item: 'WERCS Registration (battery-powered or regulated items)', required: gmfRiskLevel === 'Medium', status: 'pending', stage: 'Stage 1', category: 'gmf' },
    { item: 'UI Inspection / CE Certification (electronic items)', required: isElectronics, status: 'pending', stage: 'Stage 1', category: 'gmf' },
    { item: 'Manufacturing & Product Safety Documentation', required: true, status: 'pending', stage: 'Stage 1', category: 'gmf' }
  );
}

const requiredItems = checklist.filter(c => c.required);
const receivedItems = checklist.filter(c => c.status === 'received');

return [{ json: {
  ...d,
  complianceChecklist: checklist,
  complianceRequired: requiredItems.length,
  complianceReceived: receivedItems.length,
  complianceScore: Math.round((receivedItems.length / requiredItems.length) * 100),
  isFoodCategory: isFoodOrSupp,
  foodRiskLevel,
  gmfRiskLevel,
  riskClassification: isFoodOrSupp ? foodRiskLevel : gmfRiskLevel,
  approvedTestLabs: isFoodOrSupp ? [] : [
    { name: 'UL', contact: 'rog.hardlinessalesforcecustomerservice@ul.com' },
    { name: 'SGS', contact: 'james.dorsey@sgs.com' },
    { name: 'Intertek (ITS)', contact: 'jennifer.jenkins@intertek.com' },
    { name: 'Bureau Veritas (BV)', contact: 'ryan.deleon@bureauveritas.com' }
  ],
  phase: 2,
  phase2StartedAt: new Date().toISOString()
} }];

const d = $input.first().json;
const received = d.documents || [];
const category = (d.category || '').toLowerCase();
const isFoodOrSupp = category.includes('food') || category.includes('beverage') || category.includes('supplement') || category.includes('wellness');

// Build required docs list based on category
let requiredDocs;
if (isFoodOrSupp) {
  requiredDocs = [
    'Agreement', 'Insurance', 'Photos', 'UPC', 'ProductSpec', 'COGS', 'PnL',
    'FoodSafetyQuestionnaire', 'GFSI', 'HealthPermit', 'FoodSafetyManager',
    'FoodHandlerPermit', 'FDA', 'AllergenStatement', 'FoodPrepSOP',
    'EquipmentList', 'StorageMethod', 'FoodSafetyTraining', 'SamplingPlan'
  ];
} else {
  requiredDocs = [
    'Agreement', 'Insurance', 'Photos', 'UPC', 'ProductSpec', 'COGS', 'PnL',
    'C63ProductTesting', 'PerformanceTesting', 'RegulatoryCompliance',
    'PackagingApproval', 'StructuralPackaging', 'Manufacturing'
  ];
}

const gaps = requiredDocs.filter(r => !received.some(doc => doc.toLowerCase().includes(r.toLowerCase())));
const complianceScore = Math.round(((requiredDocs.length - gaps.length) / requiredDocs.length) * 100);

return [{ json: { ...d, receivedDocs: received, gaps, complianceScore, complianceClear: gaps.length === 0, totalRequired: requiredDocs.length, totalReceived: requiredDocs.length - gaps.length, phase: 2 } }];
